sys_ux_client_script.script:
/**
 * @param {params} params
 * @param {api} params.api
 * @param {any} params.event
 * @param {any} params.imports
 * @param {ApiHelpers} params.helpers
 */
function handler({
    api,
    event,
    helpers,
    imports
}) {
    api.setState('isLoading', false);
    const proc = api.data.process_nextform_data;
    const rawOutput = proc && proc.output && proc.output.result !== undefined && proc.output.result !== null ?
        proc.output.result :
        proc && proc.output;
    const body = rawOutput && typeof rawOutput === 'object' ? rawOutput : {};

    const processorReportedFailure = typeof body.success !== 'undefined' && body.success === false;

    if (processorReportedFailure) {
        const msg = body.message && String(body.message).length ?
            String(body.message) :
            'NextForm processor reported success: false';
        console.error('NextForm process failed:', msg, body);
        api.emit('CTRL_NEXTFORM#PROCESSING_FAILED');
    } else {
        // Advance baselines so processEditedOnly has the correct (presumably new) original values.
        const fields = api.state.fields;
        if (fields && typeof fields === 'object') {
            const synced = {};
            Object.keys(fields).forEach(function(key) {
                const field = fields[key];
                if (field && typeof field === 'object' && field.isDataField !== false &&
                    Object.hasOwn(field, 'originalValue')) {
                    synced[key] = Object.assign({}, field, {
                        originalValue: field.value
                    });
                } else {
                    synced[key] = field;
                }
            });
            api.setState('fields', synced);
        }
        api.setState('isProcessed', true);
        api.emit('CTRL_NEXTFORM#PROCESSING_COMPLETED');
    }
}
